export class DB {
  static patients = [...INITIAL_PATIENTS];
  static funding = [...INITIAL_FUNDING];
  static sessions: DialysisSession[] = [];
  static services = [...INITIAL_SERVICES];
  static invoices: Invoice[] = [];
  static stores = [...INITIAL_STORES];
  static products = [...INITIAL_PRODUCTS];
  static stockTransactions: StockTransaction[] = [];
  static employees = [...INITIAL_EMPLOYEES];
  static shifts: ShiftRecord[] = [];
  static accounts = [...INITIAL_ACCOUNTS];
  static transactions: Transaction[] = [];
  static labs: LabTest[] = [];
  static logs: AuditLog[] = [];

  static addPatient(p: Patient) { 
    this.patients = [p, ...this.patients]; 
    this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
  }

  static addSession(s: DialysisSession) { 
    this.sessions = [s, ...this.sessions];
    this.log('جلسة غسيل', `مريض ID: ${s.patientId} في غرفة ${s.room}`);
  }

  static addInvoice(inv: Invoice) { 
    this.invoices = [inv, ...this.invoices];
    this.log('إصدار فاتورة', `بمبلغ ${inv.totalAmount} للمريض ${inv.patientId}`);
  }

  static addStockTx(tx: StockTransaction) { 
    this.stockTransactions = [tx, ...this.stockTransactions];
    // Simple balance adjustment simulation
    this.log('حركة مخزنية', `نوع: ${tx.type}, صنف: ${tx.productId}, كمية: ${tx.quantity}`);
  }

  static addFinanceTx(tx: Transaction) { 
    this.transactions = [tx, ...this.transactions];
    const account = this.accounts.find(a => a.id === tx.accountId);
    if (account) {
      account.balance += (tx.type === 'INCOME' ? tx.amount : -tx.amount);
    }
    this.log('حركة مالية', `${tx.type === 'INCOME' ? 'إيداع' : 'صرف'}: ${tx.amount}`);
  }

  static log(action: string, details: string) {
    this.logs.unshift({
      id: Math.random().toString(36).substr(2, 9),
      userId: 'current-user',
      action,
      details,
      timestamp: new Date().toISOString()
    });
  }

  static resetShifts() {
    this.shifts = [];
    this.log('تصفير رواتب', 'تم تصفير بيانات الشفتات المؤقتة');
  }
}

import React, { useState } from 'react';
import { AR } from '../constants';
import { DB } from '../store';
import { Users, Upload, Download, RotateCcw, Archive, DollarSign, Wallet } from 'lucide-react';

const PayrollModule: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'payroll'>('payroll');

  const calculateSalary = (empId: string) => {
    const emp = DB.employees.find(e => e.id === empId);
    if (!emp) return 0;
    const shiftCount = DB.shifts
      .filter(s => s.employeeId === empId)
      .reduce((acc, curr) => acc + curr.count, 0);
    return shiftCount * emp.shiftPrice;
  };

  const totalMonthlyPayroll = DB.employees.reduce((acc, emp) => acc + calculateSalary(emp.id), 0);

  return (
    <div className="space-y-6">
      <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
        <button 
          onClick={() => setActiveTab('payroll')}
          className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'payroll' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
        >
          {AR.payroll}
        </button>
        <button 
          onClick={() => setActiveTab('employees')}
          className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'employees' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
        >
          {AR.employees}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border-r-4 border-blue-500">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-100 text-blue-600 rounded-xl"><Users /></div>
            <div>
              <div className="text-sm text-gray-500">عدد الموظفين</div>
              <div className="text-2xl font-bold">{DB.employees.length}</div>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border-r-4 border-green-500">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-100 text-green-600 rounded-xl"><DollarSign /></div>
            <div>
              <div className="text-sm text-gray-500">إجمالي رواتب الشهر</div>
              <div className="text-2xl font-bold">{totalMonthlyPayroll.toLocaleString()} ج.م</div>
