  static users = [...INITIAL_USERS];
  static funding = [...INITIAL_FUNDING];
  static sessions: DialysisSession[] = [];
  static services = [...INITIAL_SERVICES];
  static invoices: Invoice[] = [];
  static stores = [...INITIAL_STORES];
  static products = [...INITIAL_PRODUCTS];
  static stockTransactions: StockTransaction[] = [];
  static employees = [...INITIAL_EMPLOYEES];
  static shifts: ShiftRecord[] = [];
  static accounts = [...INITIAL_ACCOUNTS];
  static transactions: Transaction[] = [];
  static labs: LabTest[] = [];
  static logs: AuditLog[] = [];

  static addUser(u: User) {
    this.users = [u, ...this.users];
    this.log('إضافة مستخدم', `تم إضافة مستخدم جديد: ${u.name} بصلاحية ${u.role}`);
  }

  static deleteUser(id: string) {
    const user = this.users.find(u => u.id === id);
    this.users = this.users.filter(u => u.id !== id);
    if (user) this.log('حذف مستخدم', `تم حذف المستخدم: ${user.name}`);
  }

  static addPatient(p: Patient) { 
    this.patients = [p, ...this.patients]; 
    this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
  }

  static addSession(s: DialysisSession) { 
    this.sessions = [s, ...this.sessions];
    this.log('جلسة غسيل', `مريض ID: ${s.patientId} في غرفة ${s.room}`);
  }

  static addInvoice(inv: Invoice) { 
    this.invoices = [inv, ...this.invoices];
    this.log('إصدار فاتورة', `بمبلغ ${inv.totalAmount} للمريض ${inv.patientId}`);
  }

  static addStockTx(tx: StockTransaction) { 
    this.stockTransactions = [tx, ...this.stockTransactions];
    // Simple balance adjustment simulation
    this.log('حركة مخزنية', `نوع: ${tx.type}, صنف: ${tx.productId}, كمية: ${tx.quantity}`);
  }

  static addFinanceTx(tx: Transaction) { 
    this.transactions = [tx, ...this.transactions];
    const account = this.accounts.find(a => a.id === tx.accountId);
    if (account) {
      account.balance += (tx.type === 'INCOME' ? tx.amount : -tx.amount);
    }
    this.log('حركة مالية', `${tx.type === 'INCOME' ? 'إيداع' : 'صرف'}: ${tx.amount}`);
  }

  static log(action: string, details: string) {
    this.logs.unshift({
      id: Math.random().toString(36).substr(2, 9),
      userId: 'current-user',
      action,
      details,
      timestamp: new Date().toISOString()
    });
  }

  static resetShifts() {
    this.shifts = [];
    this.log('تصفير رواتب', 'تم تصفير بيانات الشفتات المؤقتة');
  }
}

import React, { useState } from 'react';
import { AR, ROLES } from '../constants';
import { DB } from '../store';
import { User, Role } from '../types';
import { UserCog, ShieldCheck, UserPlus, Search, Trash2, Key, Mail, ShieldAlert, UserCheck } from 'lucide-react';

const UsersModule: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [newUser, setNewUser] = useState<Partial<User>>({ role: 'RECEPTIONIST' });

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    const user: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: newUser.name || '',
      username: newUser.username || '',
      role: newUser.role as Role || 'RECEPTIONIST'
    };
    DB.addUser(user);
    setShowAddModal(false);
    setNewUser({ role: 'RECEPTIONIST' });
  };

  const getRoleBadgeColor = (role: Role) => {
    switch (role) {
      case 'ADMIN': return 'bg-red-100 text-red-700 border-red-200';
      case 'DOCTOR': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'ACCOUNTANT': return 'bg-green-100 text-green-700 border-green-200';
      case 'STOREKEEPER': return 'bg-orange-100 text-orange-700 border-orange-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const filteredUsers = DB.users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.username.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="relative w-full md:w-96">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder="بحث عن مستخدم..." 
            className="w-full pr-10 pl-4 py-3 border rounded-xl bg-white shadow-sm outline-none focus:ring-2 focus:ring-primary-500"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-primary-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-primary-700 transition-all font-bold shadow-md"
        >
          <UserPlus size={20} />
          {AR.newUser}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredUsers.map(user => (
          <div key={user.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 hover:shadow-md transition-all group">
            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-primary-100 text-primary-600 rounded-2xl flex items-center justify-center font-bold text-xl border border-primary-50">
                  {user.name[0]}
                </div>
                <div>
                  <h4 className="font-bold text-gray-800 text-lg">{user.name}</h4>
                  <p className="text-gray-400 text-sm flex items-center gap-1">
                    <UserCog size={14} /> @{user.username}
                  </p>
                </div>
              </div>
              <span className={`px-3 py-1 rounded-full text-xs font-bold border ${getRoleBadgeColor(user.role)}`}>
                {ROLES[user.role]}
              </span>
            </div>

            <div className="grid grid-cols-2 gap-2 mt-6">
              <button className="flex items-center justify-center gap-2 py-2 bg-gray-50 text-gray-600 rounded-lg text-sm font-bold hover:bg-gray-100">
                <Key size={14} /> كلمة السر
              </button>
              <button 
                onClick={() => { if(confirm(AR.confirmation)) DB.deleteUser(user.id); }}
                className="flex items-center justify-center gap-2 py-2 bg-red-50 text-red-600 rounded-lg text-sm font-bold hover:bg-red-100"
              >
                <Trash2 size={14} /> {AR.delete}
              </button>
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold flex items-center gap-2">
                <UserCheck size={22} /> إضافة حساب جديد
              </h3>
              <button onClick={() => setShowAddModal(false)} className="text-white hover:opacity-75">
                <UserPlus size={24} className="rotate-45" />
              </button>
            </div>
            <div className="p-8">
              <form onSubmit={handleAddUser} className="space-y-4">
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">{AR.name}</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-primary-500 outline-none"
                    onChange={e => setNewUser({...newUser, name: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">{AR.username}</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-primary-500 outline-none"
                    onChange={e => setNewUser({...newUser, username: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">{AR.role}</label>
                  <select 
                    className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-primary-500 outline-none"
                    onChange={e => setNewUser({...newUser, role: e.target.value as Role})}
                    defaultValue="RECEPTIONIST"
                  >
                    {Object.entries(ROLES).map(([key, val]) => (
                      <option key={key} value={key}>{val}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">{AR.password}</label>
                  <input 
                    required 
                    type="password" 
                    className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-primary-500 outline-none"
                  />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 py-3 bg-gray-100 rounded-lg font-bold text-gray-600">إلغاء</button>
                  <button type="submit" className="flex-1 py-3 bg-primary-600 text-white rounded-lg font-bold shadow-md hover:bg-primary-700">حفظ الحساب</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersModule;

